"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[360],{3890:e=>{e.exports=JSON.parse('{"functions":[{"name":"ComputeDistanceFalloff","desc":"Computes the intensity at `distance` from a source after free-space\\npropagation, before any geometric occlusion.\\n\\nUses a normalized inverse-square formula:\\n\\n```\\nintensity(d) = I\u2080 \xd7 (1 - (d / R)\xb2)\\n```\\n\\nThis gives full source intensity at `d = 0` and zero at `d = R`, with a\\nsmooth physically-motivated curve in between.\\n\\nPure function \u2014 no state, no side effects.","params":[{"name":"sourceIntensity","desc":"Source intensity at origin, 0\u2013100 scale.","lua_type":"number"},{"name":"sourceRadius","desc":"Maximum propagation distance in studs.","lua_type":"number"},{"name":"distance","desc":"Actual distance from source to listener in studs.","lua_type":"number"}],"returns":[{"desc":"Intensity after distance falloff, 0\u2013100.","lua_type":"number"}],"function_type":"static","source":{"line":70,"path":"docs/SoundPropagator.lua"}},{"name":"ComputeOcclusion","desc":"Computes the transmission factor through all geometry between two points.\\n\\nReturns a multiplier between 0 and 1:\\n- `1.0` \u2014 completely clear path\\n- `0.5` \u2014 half the intensity is transmitted\\n- `~0` \u2014 heavily blocked (never exactly 0 by Beer-Lambert math)\\n\\nIn `Full` accuracy, the function performs a multi-segment ray march,\\nmeasures each intersected geometry piece using a backward-ray technique,\\nand accumulates `thickness \xd7 material_coefficient` per segment. In\\n`Simple` accuracy, a single raycast is fired and a fixed attenuation is\\napplied on hit. In `Skip`, returns `1.0` immediately.","params":[{"name":"sourcePos","desc":"Sound emission origin.","lua_type":"Vector3"},{"name":"listenerPos","desc":"Listener position.","lua_type":"Vector3"},{"name":"frequency","desc":"`\\"low\\"` | `\\"mid\\"` | `\\"high\\"` \u2014 determines which absorption coefficients are used.","lua_type":"string"},{"name":"excludeList","desc":"Instances excluded from raycasts (e.g. the emitting character).","lua_type":"{ Instance }"},{"name":"accuracy","desc":"One of `SoundPropagator.Accuracy`. Defaults to `Full`.","lua_type":"string?"}],"returns":[{"desc":"Transmission factor, 0\u20131.","lua_type":"number"}],"function_type":"static","source":{"line":95,"path":"docs/SoundPropagator.lua"}},{"name":"ComputeEffectiveIntensity","desc":"Computes the effective intensity of a [SoundEmission] at a listener\\nposition, running both propagation stages in sequence.\\n\\nThis is the primary function external systems call. Returns three values:\\neffective intensity, transmission factor, and straight-line distance.\\n\\nIf the accuracy parameter is omitted, the tier is selected automatically\\nbased on normalized distance (Full for \u226450%, Simple for 50\u2013100%).","params":[{"name":"emission","desc":"The emission to evaluate.","lua_type":"SoundEmission"},{"name":"listenerPos","desc":"The listener\'s world position.","lua_type":"Vector3"},{"name":"excludeList","desc":"Instances excluded from occlusion raycasts.","lua_type":"{ Instance }"},{"name":"accuracy","desc":"Optional accuracy tier override.","lua_type":"string?"}],"returns":[{"desc":"Effective intensity at listener, 0\u2013100.","lua_type":"number"},{"desc":"Transmission (occlusion) factor, 0\u20131.","lua_type":"number"},{"desc":"Straight-line distance from source to listener, in studs.","lua_type":"number"}],"function_type":"static","source":{"line":117,"path":"docs/SoundPropagator.lua"}},{"name":"RecommendAccuracy","desc":"Returns the recommended accuracy tier for a given emission and listener\\ndistance.\\n\\n| Normalised distance | Tier |\\n|---------------------|------|\\n| `>= 1.0` (at or beyond radius) | `Skip` |\\n| `0.5 \u2013 1.0` | `Simple` |\\n| `< 0.5` | `Full` |","params":[{"name":"emission","desc":"","lua_type":"SoundEmission"},{"name":"distance","desc":"Distance from source to listener in studs.","lua_type":"number"}],"returns":[{"desc":"One of `SoundPropagator.Accuracy`.","lua_type":"string"}],"function_type":"static","source":{"line":135,"path":"docs/SoundPropagator.lua"}}],"properties":[{"name":"Accuracy","desc":"Accuracy tier constants. Pass these to [SoundPropagator.ComputeOcclusion]\\nor [SoundPropagator.ComputeEffectiveIntensity] to override the\\nauto-selected tier.\\n\\n| Value | Meaning |\\n|-------|---------|\\n| `Full` | Multi-segment ray march with per-material frequency absorption. Most accurate. |\\n| `Simple` | Single raycast with fixed conservative attenuation on hit. |\\n| `Skip` | No occlusion check \u2014 returns `1.0` immediately. |","lua_type":"{ Full: string, Simple: string, Skip: string }","source":{"line":47,"path":"docs/SoundPropagator.lua"}}],"types":[],"name":"SoundPropagator","desc":"Pure physics layer for acoustic propagation simulation.\\n\\nEvery function in this module is pure in the strict sense: no state is\\nread or written, no signals are fired, and given the same inputs (except\\nfor workspace raycasts which depend on geometry), it always produces the\\nsame outputs. It can be called safely from any context.\\n\\n**Two-stage propagation model:**\\n\\nStage 1 \u2014 Distance falloff. Sound energy disperses according to the\\ninverse square law, normalized to the emission\'s configured radius.\\nO(1), no raycasting.\\n\\nStage 2 \u2014 Geometric occlusion. Sound energy is absorbed as it passes\\nthrough solid geometry. Uses Beer-Lambert exponential decay with\\nper-material, per-frequency absorption coefficients.\\n\\n**Accuracy tiers:**\\n\\n| Tier | When used | Raycasts |\\n|------|-----------|----------|\\n| `Full` | Listener within 50% of radius | Up to 12 (ray march + thickness probes) |\\n| `Simple` | Listener 50\u2013100% of radius | 1 |\\n| `Skip` | Beyond radius or budget exceeded | 0 |","source":{"line":29,"path":"docs/SoundPropagator.lua"}}')}}]);